Def:
(
    (
        if(
            vSetDate = vCurrentYearMonth,
            Sum({<[MilestoneDateType]={'$(vCurrentMilestoneDateName)'},[$(vCurrentMilestoneDateName) Milestone Date MTD Flag]={Yes}>}[Loan Amount]),
            Sum({<[MilestoneDateType]={'$(vCurrentMilestoneDateName)'},[$(vCurrentMilestoneDateName) Milestone Date]={">=$(=MonthStart(vSetDateCalc))<=$(=MonthEnd(vSetDateCalc))"}>}[Loan Amount])
        )
        -
        Sum({<[MilestoneDateType]={'$(vCurrentMilestoneDateName)'},[$(vCurrentMilestoneDateName) Milestone Date]={">=$(=MonthStart(AddMonths(vSetDateCalc,-1)))<=$(=MonthEnd(AddMonths(vSetDateCalc,-1)))"}>}[Loan Amount])
    )
    /
    Sum({<[MilestoneDateType]={'$(vCurrentMilestoneDateName)'},[$(vCurrentMilestoneDateName) Milestone Date]={">=$(=MonthStart(AddMonths(vSetDateCalc,-1)))<=$(=MonthEnd(AddMonths(vSetDateCalc,-1)))"}>}[Loan Amount])
)

DefExpanded:
(
    (
        if(
            vSetDate = vCurrentYearMonth,
            Sum({<[MilestoneDateType]={''},[ Milestone Date MTD Flag]={Yes}>}[Loan Amount]),
            Sum({<[MilestoneDateType]={''},[ Milestone Date]={">=-<=-"}>}[Loan Amount])
        )
        -
        Sum({<[MilestoneDateType]={''},[ Milestone Date]={">=-<=-"}>}[Loan Amount])
    )
    /
    Sum({<[MilestoneDateType]={''},[ Milestone Date]={">=-<=-"}>}[Loan Amount])
)
